module dual_port_ram #(
    parameter DEPTH = 16,
    parameter WIDTH = 8,
    parameter ADDR_WIDTH = $clog2(DEPTH)
)(
    input wclk,
    input wenc,
    input [ADDR_WIDTH-1:0] waddr,
    input [WIDTH-1:0] wdata,
    input rclk,
    input rinc,
    input [ADDR_WIDTH-1:0] raddr,
    output [WIDTH-1:0] rdata
);

    reg [WIDTH-1:0] mem [DEPTH-1:0];
    reg [DEPTH-1:0] rflags;

    always @(posedge wclk) begin
        if (wenc) begin
            mem[waddr] <= wdata;
        end
    end

    always @(posedge rclk) begin
        if (rinc) begin
            rflags[raddr] <= 1'b1;
        end else begin
            rflags[raddr] <= 1'b0;
        end
    end

    assign rdata = mem[raddr] & {WIDTH{rflags[raddr]}};

endmodule
